function getBodyParts(payload) {
  const parts = { html: '', text: '' };

  function decode(data) {
    if (!data) return '';
    const base64 = data.replace(/-/g, '+').replace(/_/g, '/');
    return Buffer.from(base64, 'base64').toString('utf-8');
  }

  function traverse(part) {
    if (!part) return;
    if (part.mimeType === 'text/html' && part.body?.data) {
      parts.html = decode(part.body.data);
    } else if (part.mimeType === 'text/plain' && part.body?.data) {
      parts.text = decode(part.body.data);
    }
    if (part.parts) part.parts.forEach(traverse);
  }

  traverse(payload);
  return parts;
}

return items.map(item => {
  const json = item.json;

  const headers = json.payload?.headers || [];
  const getHeader = name => headers.find(h => h.name.toLowerCase() === name.toLowerCase())?.value || '';

  const subject = getHeader('subject') || 'Untitled newsletter';
  const from = getHeader('from') || 'Unknown sender';
  const date = getHeader('date') || new Date().toISOString();

  const senderEmail = (
    from.match(/[\w.+-]+@[\w.-]+/)?.[0] || 'unknown'
  ).toLowerCase();

  const senderSlug = senderEmail
    .replace(/@.*$/, '')
    .replace(/[^a-z0-9]+/g, '-')
    .slice(0, 40);

  const { html, text } = getBodyParts(json.payload);

  const sourceMessageId = json.id || `${senderEmail}-${subject}-${date}`;

  return {
    json: { subject, from, senderEmail, senderSlug, date, html, text, sourceMessageId },
  };
});

const output = [];

for (let i = 0; i < items.length; i++) {
  const responseText = items[i].json.text || items[i].json.response || '';
  const directLinks = items[i].json.links;

  const emailData = $('Normalize Email').all()[i]?.json || {};
  const { subject, from: senderFrom, senderEmail, senderSlug, date, sourceMessageId } = emailData;

  let links = [];
  if (Array.isArray(directLinks) && directLinks.length > 0) {
    links = directLinks;
  } else if (responseText) {
    try {
      let jsonStr = responseText;
      const codeBlockMatch = jsonStr.match(/```(?:json)?\s*([\s\S]*?)```/);
      if (codeBlockMatch) jsonStr = codeBlockMatch[1];
      const parsed = JSON.parse(jsonStr.trim());
      links = parsed.links || parsed;
    } catch (e) {
      const jsonMatch = responseText.match(/\{[\s\S]*"links"[\s\S]*\}/);
      if (jsonMatch) {
        try { links = JSON.parse(jsonMatch[0]).links || []; } catch {}
      }
    }
  }

  if (!Array.isArray(links)) links = [];

  for (const link of links) {
    if (!link.url) continue;
    output.push({
      json: {
        url: link.url,
        title: link.title || link.url,
        description: link.description || '',
        anchorText: link.title || '',
        newsletterSubject: subject,
        newsletterFrom: senderFrom,
        senderEmail,
        senderSlug,
        newsletterDate: date,
        sourceMessageId,
      },
    });
  }
}

return output;

const seen = new Set();
const output = [];
for (const item of items) {
  const key = item.json.url;
  if (seen.has(key)) continue;
  seen.add(key);
  output.push(item);
}
return output;

const fs = require('fs');
const feedToken = process.env.FEED_TOKEN;
const statePath = `/feeds/${feedToken}/state.json`;

let existingItems = [];
if (fs.existsSync(statePath)) {
  try { existingItems = JSON.parse(fs.readFileSync(statePath, 'utf8')); } catch { existingItems = []; }
}

return [{ json: { existingItems, newItems: items.map(i => i.json), feedToken } }];

const crypto = require('crypto');

function guidForUrl(url) {
  return crypto.createHash('sha256').update(url).digest('hex').slice(0, 32);
}

const { existingItems, newItems, feedToken } = items[0].json;
const byGuid = new Map();

for (const item of existingItems) byGuid.set(item.guid, item);

let addedCount = 0;
for (const item of newItems) {
  const guid = guidForUrl(item.url);
  if (byGuid.has(guid)) continue;
  byGuid.set(guid, {
    guid,
    title: item.title || item.anchorText || item.url,
    description: item.description || '',
    link: item.url,
    pubDate: new Date(item.newsletterDate || Date.now()).toUTCString(),
    sourceNewsletter: item.newsletterSubject,
    sourceFrom: item.newsletterFrom,
    senderSlug: item.senderSlug,
    senderEmail: item.senderEmail,
    addedAt: new Date().toISOString(),
  });
  addedCount++;
}

const merged = [...byGuid.values()].sort((a, b) => new Date(b.addedAt) - new Date(a.addedAt)).slice(0, 500);

return [{ json: { items: merged, feedToken, addedCount, totalCount: merged.length } }];

const fs = require('fs');
const path = require('path');

function escapeXml(value) {
  return String(value || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&apos;');
}

function extractDomain(email) {
  if (!email) return null;
  const match = email.match(/@([^>\s]+)/);
  return match ? match[1] : null;
}

function extractSenderName(from) {
  if (!from) return null;
  const nameMatch = from.match(/^\s*"?([^"<]+?)"?\s*</);
  return nameMatch ? nameMatch[1].trim() : from.replace(/<[^>]+>/, '').trim() || null;
}

function generateRss(feedTitle, feedDescription, feedLink, feedItems, imageUrl) {
  const rssItems = feedItems.map(item => `  <item>
    <title>${escapeXml(item.title)}</title>
    <link>${escapeXml(item.link)}</link>
    <guid isPermaLink="false">${escapeXml(item.guid)}</guid>
    <pubDate>${item.pubDate}</pubDate>
    <description>${escapeXml((item.description ? item.description + ' — ' : '') + 'From: ' + (item.sourceNewsletter || 'newsletter') + ' (' + (item.sourceFrom || '') + ')')}</description>
    <source url="${escapeXml(feedLink)}">${escapeXml(item.sourceNewsletter || 'Newsletter')}</source>
  </item>`).join('\n');

  const imageBlock = imageUrl ? `
  <image>
    <url>${escapeXml(imageUrl)}</url>
    <title>${escapeXml(feedTitle)}</title>
    <link>${escapeXml(feedLink)}</link>
  </image>` : '';

  return `<?xml version="1.0" encoding="UTF-8"?>
<rss version="2.0" xmlns:atom="http://www.w3.org/2005/Atom">
<channel>
  <title>${escapeXml(feedTitle)}</title>
  <link>${escapeXml(feedLink)}</link>
  <description>${escapeXml(feedDescription)}</description>
  <language>en</language>
  <lastBuildDate>${new Date().toUTCString()}</lastBuildDate>
  <atom:link href="${escapeXml(feedLink)}" rel="self" type="application/rss+xml"/>${imageBlock}
${rssItems}
</channel>
</rss>`;
}

const { items: feedItems, feedToken, addedCount, totalCount } = items[0].json;
const feedsDir = `/feeds/${feedToken}`;
const feedsDomain = process.env.FEEDS_DOMAIN || 'feeds.example.com';
const baseUrl = `https://${feedsDomain}/${feedToken}`;

fs.mkdirSync(feedsDir, { recursive: true });

const allXml = generateRss('Newsletter Links', 'All links extracted from newsletters', `${baseUrl}/all.xml`, feedItems);
fs.writeFileSync(path.join(feedsDir, 'all.xml'), allXml, 'utf8');

const bySlug = {};
for (const item of feedItems) {
  const slug = item.senderSlug || 'unknown';
  if (!bySlug[slug]) bySlug[slug] = [];
  bySlug[slug].push(item);
}

const feedFiles = ['all.xml'];
for (const [slug, slugItems] of Object.entries(bySlug)) {
  const filename = `${slug}.xml`;
  const domain = extractDomain(slugItems[0]?.senderEmail || slugItems[0]?.sourceFrom || '');
  const faviconUrl = domain ? `https://www.google.com/s2/favicons?domain=${domain}&sz=128` : null;
  const senderName = extractSenderName(slugItems[0]?.sourceFrom) || slug;
  const xml = generateRss(`${senderName} Links`, `Links from ${senderName}`, `${baseUrl}/${filename}`, slugItems, faviconUrl);
  fs.writeFileSync(path.join(feedsDir, filename), xml, 'utf8');
  feedFiles.push(filename);
}

fs.writeFileSync(path.join(feedsDir, 'state.json'), JSON.stringify(feedItems, null, 2), 'utf8');

return [{ json: { status: 'ok', addedCount, totalCount, feedFiles, combinedFeedUrl: `${baseUrl}/all.xml`, perNewsletterFeeds: Object.keys(bySlug).map(s => `${baseUrl}/${s}.xml`) } }];
